#include <iostream>
#include <cstring>
#include <vector>
#include <cctype>

struct TestCase {
    const char* input;
    const char* expected;
};

int main() {
    std::vector<TestCase> testCases = {
        {"Hello World!", "HELLO WORLD!"},
        {"test123ABC", "TEST123ABC"},
        {"", ""},
        {"ALLCAPS", "ALLCAPS"},
        {"mixed Case StrinG", "MIXED CASE STRING"}
    };

    bool allTestsPassed = true;
    for (size_t i = 0; i < testCases.size(); ++i) {
        char* buffer = new char[strlen(testCases[i].input) + 1];
        strcpy(buffer, testCases[i].input);

        strToUpper(buffer);

        if (strcmp(buffer, testCases[i].expected) != 0) {
            allTestsPassed = false;
        }
        delete[] buffer;
    }

    char exampleString[] = "This is an Example String for Demonstration.";
    strToUpper(exampleString);

    return allTestsPassed ? 0 : 1;
}
